class Solution:
    def subsets(self, nums: list[int]) -> list[list[int]]:
        result = [[]]

        for num in nums:
            # for each existing subset, add a new one with num appended
            result += [subset + [num] for subset in result]

        return result

class Solution:
    def permute(self, nums: list[int]) -> list[list[int]]:
        result = []
        perm = []
        used = set()

        def backtrack():
            if len(perm) == len(nums):
                result.append(perm[:])
                return

            for i in range(len(nums)):
                if i in used:
                    continue

                perm.append(nums[i])
                used.add(i)
                backtrack()
                perm.pop()
                used.remove(i)

        backtrack()
        return result

class Solution:
    def permute(self, nums: list[int]) -> list[list[int]]:
        result = []

        def backtrack(start):
            if start == len(nums):
                result.append(nums[:])
                return

            for i in range(start, len(nums)):
                # swap nums[start] with nums[i]
                nums[start], nums[i] = nums[i], nums[start]
                backtrack(start + 1)
                # backtrack: swap back
                nums[start], nums[i] = nums[i], nums[start]

        backtrack(0)
        return result

class Solution:
    def permute(self, nums: list[int]) -> list[list[int]]:
        from itertools import permutations
        # permutations returns tuples, convert to lists
        return [list(p) for p in permutations(nums)]

class Solution:
    def combinationSum2(self, candidates: list[int], target: int) -> list[list[int]]:
        candidates.sort()
        result = []
        combo = []

        def backtrack(i, total):
            if total == target:
                result.append(combo[:])
                return
            if total > target:
                return

            for j in range(i, len(candidates)):
                if j > i and candidates[j] == candidates[j - 1]:
                    continue  # skip duplicates at this level
                combo.append(candidates[j])
                backtrack(j + 1, total + candidates[j])  # j+1: no reuse
                combo.pop()

        backtrack(0, 0)
        return result

class Solution:
    def exist(self, board: list[list[str]], word: str) -> bool:
        rows, cols = len(board), len(board[0])

        def backtrack(r, c, i):
            if i == len(word):
                return True
            if r < 0 or r >= rows or c < 0 or c >= cols or board[r][c] != word[i]:
                return False

            # mark visited
            temp = board[r][c]
            board[r][c] = '#'

            # explore 4 directions
            found = (backtrack(r + 1, c, i + 1) or
                     backtrack(r - 1, c, i + 1) or
                     backtrack(r, c + 1, i + 1) or
                     backtrack(r, c - 1, i + 1))

            # backtrack
            board[r][c] = temp
            return found

        for r in range(rows):
            for c in range(cols):
                if backtrack(r, c, 0):
                    return True
        return False

class Solution:
    def partition(self, s: str) -> list[list[str]]:
        result = []
        partition = []

        def is_palindrome(sub):
            return sub == sub[::-1]

        def backtrack(start):
            if start == len(s):
                result.append(partition[:])
                return

            for end in range(start + 1, len(s) + 1):
                substring = s[start:end]
                if is_palindrome(substring):
                    partition.append(substring)
                    backtrack(end)
                    partition.pop()

        backtrack(0)
        return result

class Solution:
    def partition(self, s: str) -> list[list[str]]:
        n = len(s)
        # DP table: is_palindrome[i][j] = True if s[i:j+1] is a palindrome
        is_palindrome = [[False] * n for _ in range(n)]

        # every single character is a palindrome
        for i in range(n):
            is_palindrome[i][i] = True

        # check for length 2
        for i in range(n - 1):
            if s[i] == s[i + 1]:
                is_palindrome[i][i + 1] = True

        # check for lengths 3 to n
        for length in range(3, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if s[i] == s[j] and is_palindrome[i + 1][j - 1]:
                    is_palindrome[i][j] = True

        result = []
        partition = []

        def backtrack(start):
            if start == n:
                result.append(partition[:])
                return

            for end in range(start, n):
                if is_palindrome[start][end]:
                    partition.append(s[start:end + 1])
                    backtrack(end + 1)
                    partition.pop()

        backtrack(0)
        return result

class Solution:
    def letterCombinations(self, digits: str) -> list[str]:
        if not digits:
            return []

        phone = {
            '2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl',
            '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'
        }
        result = []
        combo = []

        def backtrack(i):
            if i == len(digits):
                result.append(''.join(combo))
                return

            for letter in phone[digits[i]]:
                combo.append(letter)
                backtrack(i + 1)
                combo.pop()

        backtrack(0)
        return result

