class Solution:
    def solveSudoku(self, board: List[List[str]]) -> None:
        emptyPlaces = [(i,j) for i in range(9) for j in range(9) if board[i][j]=="."]    

        def isValidMove(i, j, num):
            if any(board[i][col]==num for col in range(9)): return False #check row
            if any(board[row][j]==num for row in range(9)): return False #check col
            blockRow, blockCol = (i//3)*3, (j//3)*3 #check block of num
            if any(board[row][col]==num for row in range(blockRow, blockRow+3) for col in range(blockCol, blockCol+3)): return False
            return True

        def sudokuSolver(index):
            if index==len(emptyPlaces): return True
            i, j = emptyPlaces[index]  
            for num in range(1, 10):
                if isValidMove(i, j, str(num)):
                    board[i][j] = str(num)
                    if sudokuSolver(index + 1): return True
                    board[i][j] = "."
            return False

        sudokuSolver(0)


# Key Idea: use rowVisited, colVisited, blockVisited for faster checking

class Solution:
    def solveSudoku(self, board: List[List[str]]) -> None:
        emptyPlaces, rowVisited, colVisited, blockVisited = [], defaultdict(set), defaultdict(set), defaultdict(set)
        for i in range(9):
            for j in range(9):
                if board[i][j]==".": emptyPlaces.append((i,j))
                else: 
                    rowVisited[i].add(board[i][j])             
                    colVisited[j].add(board[i][j])             
                    blockVisited[((i//3)*3, (j//3)*3)].add(board[i][j])

        def sudokuSolver(index):
            if index==len(emptyPlaces): return True
            i, j = emptyPlaces[index]  
            for num in range(1, 10):
                num = str(num)
                if num not in rowVisited[i] and num not in colVisited[j] and num not in blockVisited[((i//3)*3, (j//3)*3)]:
                    board[i][j] = num
                    rowVisited[i].add(num)
                    colVisited[j].add(num)
                    blockVisited[((i//3)*3, (j//3)*3)].add(num)
                    if sudokuSolver(index + 1): return True
                    board[i][j] = "."
                    rowVisited[i].remove(num)
                    colVisited[j].remove(num)
                    blockVisited[((i//3)*3, (j//3)*3)].remove(num)
            return False

        sudokuSolver(0)

# Key Idea: Use the two prunings

class Solution:
    def exist(self, board: List[List[str]], word: str) -> bool:
        lenOfWord, m, n = len(word), len(board), len(board[0])
        charToIndicesMap = defaultdict(list)
        for i in range(m):
            for j in range(n):
                charToIndicesMap[board[i][j]].append((i,j))

        # prune 1 -> not enough chars
        counter = Counter(word)
        if any(char not in charToIndicesMap or len(charToIndicesMap[char])<counter[char] for char in counter): 
            return False

        # prune 2 -> if prefix is longer than suffix, reverse (Ex: aaaaabcc)
        prefixIndex, suffixIndex = 0, lenOfWord-1
        while prefixIndex<lenOfWord and word[prefixIndex]==word[0]: prefixIndex += 1
        while suffixIndex>=0 and word[suffixIndex]==word[lenOfWord-1]: suffixIndex -= 1
        if lenOfWord-1-suffixIndex<prefixIndex: 
            word = word[::-1]

        def findWord(i, j, wordIndex, visited):
            if wordIndex==lenOfWord: return True
            for di, dj in [[1,0],[0,1],[0,-1],[-1,0]]:
                newI, newJ = i+di, j+dj
                if 0<=newI<m and 0<=newJ<n and board[newI][newJ]==word[wordIndex] and (newI, newJ) not in visited:
                    visited.add((newI, newJ))
                    if findWord(newI, newJ, wordIndex+1, visited):
                        return True
                    visited.remove((newI, newJ))    
            return False

        if any(findWord(i, j, 1, set([(i, j)])) for i,j in charToIndicesMap[word[0]]): return True
        return False

# Key Idea: Permutation -> Brute force -> Back tracking or Bitmasking. Overlapping subproblems -> Bitmasking DP

# Optimisation: Start from right to left as there will be less numbers that can fill higher indices

class Solution:
    def countArrangement(self, n: int) -> int:

        @lru_cache(None)
        def bitmaskingDP(bitmask, indexToSetNext):
            if indexToSetNext==0: return 1
            possibilities = 0
            for number in range(1, n+1):
                # number'th position is not set and number is div or mult of numberToSetNext
                if not (bitmask & 1<<number) and (number%indexToSetNext==0 or indexToSetNext%number==0):
                    possibilities += bitmaskingDP(bitmask | 1<<number, indexToSetNext-1)
            return possibilities

        return bitmaskingDP(0, n) # Optimisation

